const fs = require("fs");
const path = require("path");

function readEnvFile(envPath) {
  try {
    if (!fs.existsSync(envPath)) {
      return {};
    }
    const dotenv = require("dotenv");
    const raw = fs.readFileSync(envPath, "utf8");
    return dotenv.parse(raw);
  } catch (_error) {
    return {};
  }
}

function normalize(value) {
  return String(value || "").trim();
}

function jsStringLiteral(value) {
  return JSON.stringify(String(value || ""));
}

function main() {
  const rootDir = path.resolve(__dirname, "..");
  const envPath = path.join(rootDir, ".env");
  const envFileVars = readEnvFile(envPath);

  const openaiKey = normalize(process.env.OPENAI_API_KEY || envFileVars.OPENAI_API_KEY || envFileVars.GPT_key);
  const geminiKey = normalize(process.env.GEMINI_API_KEY || envFileVars.GEMINI_API_KEY);

  if (!openaiKey && !geminiKey) {
    console.error(
      "[bundle] No AI keys found. Set OPENAI_API_KEY or GEMINI_API_KEY in .env (repo root) or in environment variables."
    );
    process.exit(1);
  }

  const outPath = path.join(rootDir, "src", "main", "config", "bundledSecrets.js");
  fs.mkdirSync(path.dirname(outPath), { recursive: true });

  const lines = [
    "// AUTO-GENERATED FILE — DO NOT COMMIT.",
    "// Generated by scripts/generateBundledSecrets.js",
    "// Contains API keys for packaged builds (temporary approach).",
    "",
    "module.exports = {",
    `  OPENAI_API_KEY: ${jsStringLiteral(openaiKey)},`,
    `  GEMINI_API_KEY: ${jsStringLiteral(geminiKey)}`,
    "};",
    ""
  ];

  fs.writeFileSync(outPath, lines.join("\n"), { encoding: "utf8" });

  console.log("[bundle] Bundled secrets generated.");
  console.log("[bundle] Output:", outPath);
  console.log("[bundle] Included providers:", {
    openai: Boolean(openaiKey),
    gemini: Boolean(geminiKey)
  });
}

main();

